#pragma once

#include "envoy/http/filter.h"

namespace Envoy {
namespace Http {

/**
 * A minimal HTTP filter that passes all data through with Continue status.
 * Implements the StreamDecoderFilter interface by passing through all data
 * without modification.
 */
class PassThroughFilter : public StreamDecoderFilter {
public:
  // Http::StreamFilterBase
  void onDestroy() override {}

  // Http::StreamDecoderFilter
  /**
   * Called with decoded headers. Returns Continue to pass headers through the filter chain.
   */
  FilterHeadersStatus decodeHeaders(RequestHeaderMap& headers, bool end_stream) override;

  /**
   * Called with decoded data. Returns Continue to pass data through the filter chain.
   */
  FilterDataStatus decodeData(Buffer::Instance& data, bool end_stream) override;

  /**
   * Called with decoded trailers. Returns Continue to pass trailers through the filter chain.
   */
  FilterTrailersStatus decodeTrailers(RequestTrailerMap& trailers) override;

  /**
   * Called to initialize the filter decoder callbacks. Stores the callbacks pointer
   * for potential use by the filter.
   */
  void setDecoderFilterCallbacks(StreamDecoderFilterCallbacks& callbacks) override;

protected:
  /**
   * Stores the stream decoder filter callbacks for access by derived classes.
   */
  StreamDecoderFilterCallbacks* decoder_callbacks_{};
};

} // namespace Http
} // namespace Envoy

#include "pass_through_filter.h"

namespace Envoy {
namespace Http {

FilterHeadersStatus PassThroughFilter::decodeHeaders(RequestHeaderMap&, bool) {
  return FilterHeadersStatus::Continue;
}

FilterDataStatus PassThroughFilter::decodeData(Buffer::Instance&, bool) {
  return FilterDataStatus::Continue;
}

FilterTrailersStatus PassThroughFilter::decodeTrailers(RequestTrailerMap&) {
  return FilterTrailersStatus::Continue;
}

void PassThroughFilter::setDecoderFilterCallbacks(StreamDecoderFilterCallbacks& callbacks) {
  decoder_callbacks_ = &callbacks;
}

} // namespace Http
} // namespace Envoy

#include "pass_through_filter.h"

#include "envoy/registry/registry.h"
#include "envoy/server/filter_config.h"

namespace Envoy {
namespace Http {

/**
 * Factory class for the pass-through HTTP filter.
 * Creates instances of PassThroughFilter for use in the HTTP filter chain.
 */
class PassThroughFilterConfig : public Server::Configuration::NamedHttpFilterConfigFactory {
public:
  /**
   * Creates a filter factory callback from the configuration proto.
   * @param proto_config The configuration protobuf message.
   * @param stats_prefix The prefix for statistics.
   * @param context The factory context.
   * @return A filter factory callback.
   */
  absl::StatusOr<FilterFactoryCb>
  createFilterFactoryFromProto(const Protobuf::Message& /*proto_config*/,
                               const std::string& /*stats_prefix*/,
                               Server::Configuration::FactoryContext& /*context*/) override {
    return [](FilterChainFactoryCallbacks& callbacks) -> void {
      callbacks.addStreamDecoderFilter(
          std::make_shared<PassThroughFilter>());
    };
  }

  /**
   * Returns the name of the filter.
   * @return The filter name: "envoy.filters.http.pass_through"
   */
  std::string name() const override {
    return "envoy.filters.http.pass_through";
  }

  /**
   * Creates an empty configuration proto for this filter.
   * @return An empty protobuf message.
   */
  ProtobufTypes::MessagePtr createEmptyConfigProto() override {
    return std::make_unique<Protobuf::Struct>();
  }
};

/**
 * Static registration for the pass-through HTTP filter.
 * Registers the PassThroughFilterConfig factory with the filter registry.
 */
REGISTER_FACTORY(PassThroughFilterConfig, Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace Http
} // namespace Envoy

